<!--
* @Author: zhangbo
* @Date: 2026/2/3 15:09
* @Descripttion: 自定义更多选择器
-->
<template>
  <LTPages
      :title="'自定义更多选择器'"
      isNormal
  >
    <template v-slot:content>
      <div class="Docs-Body">
        <!--说明-->
        <div class="zhb-allnum-tip">
          <i class="icon zhb-iconfont zhb-icongantanhao"></i>
          <div style="width: 100%;">element-plus 的el-input 结合el-tooltip封装的 更多选择器。</div>
        </div>
        <!--1、基本用法-->
        <div class="zhb-title">基本用法</div>
        <div style="margin-bottom:15px;width: 300px;">
          <LTInputTooltipMore
              :list="devices"
              :disabled="false"
              @clickMore="clickMore" @clear="clear"
              @delete="deletePopUp">
          </LTInputTooltipMore>
        </div>
        <!--2、代码示例-->
        <div class="zhb-title">代码示例</div>
        <!--template-->
        <codeCopy :code="mainCode" id="LTTooltip1" title="template"></codeCopy>
        <!--javaScript-->
        <codeCopy :code="jsCode" id="LTActionsForm2" title="javaScript"></codeCopy>
        <!--3、配置参数-->
        <div class="zhb-title">配置参数</div>
        <div style="margin-bottom: 30px;">
          <el-table
              :data="tableData"
              :header-cell-style="{
                background:'#0F1F43',
                fontSize:'14px',
                color:'rgba(0,0,0,.85)'
            }">
            <el-table-column prop="text1" label="参数"/>
            <el-table-column prop="text2" label="说明"/>
            <el-table-column prop="text3" label="类型"/>
            <el-table-column prop="text4" label="可选值"/>
            <el-table-column prop="text5" label="默认值"/>
            <el-table-column prop="text6" label="备注"/>

          </el-table>
        </div>





      </div>
    </template>
  </LTPages>
</template>

<script>
export default {
  data() {
    return {
      devices: [
        {label: '变电站', value: '1'},
        {label: '换流站', value: '2'}
      ],
      mainCode: `<template>
  <LTInputTooltipMore
          :list="devices"
          :disabled="false"
          @clickMore="clickMore" @clear="clear"
          @delete="deletePopUp">
      </LTInputTooltipMore>
</template>
`,
      jsCode: `export default {
  data() {
    return {
      devices: [
        {label: '变电站', value: '1'},
        {label: '换流站', value: '2'}
      ],
    }
  },

  methods: {
    clickMore(item) {
      // 点击更多
      this.$message({
        message: '点击更多',
        type: 'success'
      });
      console.log('点击更多', item);
    },
    clear(item) {
      // 清空
      this.$message({
        message: '清空',
        type: 'success'
      });
      this.devices.value = [];
      console.log('清空');
      console.log(item);
    },
    deletePopUp(index, item, node) {
      // 删除
      this.$message({
        message: '删除',
        type: 'success'
      });
      console.log('删除');
      console.log(index, item, node);
    }
  },
}`,
      // 配置参数
      tableData:[
        {
          text1:'list',
          text2:'需要展示的数据',
          text3:'Array',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'disabled',
          text2:'是否禁止选择',
          text3:'Boolean',
          text4:'---',
          text5:'false',
          text6:'---',
        },
        {
          text1:'@clickMore',
          text2:'点击事件，用于操作更多按钮',
          text3:'Funtion',
          text4:'---',
          text5:'false',
          text6:'---',
        },
        {
          text1:'@clear',
          text2:'清空展示数据',
          text3:'Funtion',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'@delete',
          text2:'单个删除展示数据',
          text3:'Funtion',
          text4:'---',
          text5:'---',
          text6:'---',
        }
      ],


    }
        
  },
  methods: {
    clickMore(item) {
      // 点击更多
      this.$message({
        message: '点击更多',
        type: 'success'
      });
      console.log('点击更多', item);
    },
    clear(item) {
      // 清空
      this.$message({
        message: '清空',
        type: 'success'
      });
      this.devices.value = [];
      console.log('清空');
      console.log(item);
    },
    deletePopUp(index, item, node) {
      // 删除
      this.$message({
        message: '删除',
        type: 'success'
      });
      console.log('删除');
      console.log(index, item, node);
    }
  },
}
</script>

